+            context,
+            name: "transmit".into(),
+            kind: SymbolSpanKind::Transmit,
+            start_time,
+            end_time: None,
+            status: SymbolSpanStatus::InProgress,
+            object_id: Some(symbol_id.object_id()),
+            symbol_id: Some(symbol_id),
+            symbol_count: None,
+            attributes: HashMap::new(),
+            error_message: None,
+        }
+    }
